    // Hero
    'hero.eyebrow': 'An interactive technical explainer',
    'hero.titleA': 'Large Language Models',
    'hero.titleB': 'From the Inside',
    'hero.subtitle': 'In 2017 a single paper called <em>Attention Is All You Need</em> proposed a network that learned by glancing across a sentence in parallel. Eight years later, descendants of that idea write code, prove theorems, hold conversations, and act through tools. This page walks the whole arc — the algorithms, the scaling, the alignment tricks, the engineering — at the level of a curious undergraduate.',
    'hero.demoLabel': 'A token stream lights up across attention heads — every position attending to every other',
    'hero.play': '▶ Play',
